// WF_SCENE_CLASSIFY — validate auth, extract params, calculate video_count.
// If video_count === 0 (ratio '100_0'), skip classification: mark all scenes has_video=false.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const payload = raw.body || raw;
const headers = raw.headers || {};

// Auth check
const authHeader = headers.authorization || headers.Authorization || '';
const expectedToken = `Bearer ${$env.DASHBOARD_API_TOKEN}`;
if (authHeader !== expectedToken) {
  return [{
    json: {
      success: false,
      error: 'Unauthorized — invalid or missing Authorization header',
      http_status: 401
    }
  }];
}

const topicId = payload.topic_id;
const videoRatio = payload.video_ratio || '100_0';
const sceneCount = parseInt(payload.scene_count || '0', 10);
const productionRegister = payload.production_register || null;

if (!topicId) {
  return [{
    json: {
      success: false,
      error: 'Provide { topic_id, video_ratio, scene_count }',
      http_status: 400
    }
  }];
}

if (sceneCount <= 0) {
  return [{
    json: {
      success: false,
      error: 'scene_count must be > 0',
      http_status: 400
    }
  }];
}

// Calculate video_count from ratio
const ratioMap = {
  '100_0': 0,
  '95_5': 0.05,
  '90_10': 0.10,
  '85_15': 0.15
};

const fraction = ratioMap[videoRatio];
if (fraction === undefined) {
  return [{
    json: {
      success: false,
      error: `Invalid video_ratio '${videoRatio}'. Must be one of: 100_0, 95_5, 90_10, 85_15`,
      http_status: 400
    }
  }];
}

const videoCount = Math.round(sceneCount * fraction);

// If video_count === 0, skip classification entirely
if (videoCount === 0) {
  const supabaseUrl = $env.SUPABASE_URL;
  const sbHeaders = {
    'apikey': $env.SUPABASE_ANON_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json'
  };

  // Set all scenes to has_video=false, scene_classification='static_optimal'
  try {
    await fetch(`${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        has_video: false,
        scene_classification: 'static_optimal',
        classification_reasoning: 'Video ratio 100_0 — all scenes static'
      })
    });
  } catch (e) {
    return [{
      json: {
        success: false,
        error: `Failed to patch scenes for 100_0 ratio: ${e.message}`,
        http_status: 500
      }
    }];
  }

  // Log completion
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        topic_id: topicId,
        stage: 'scene_classify',
        scene_number: null,
        action: 'skip_all_static',
        status: 'success',
        duration_ms: 0,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { /* logging best-effort */ }

  return [{
    json: {
      success: true,
      production_register: productionRegister,
      message: 'All scenes set to static (video_ratio=100_0, video_count=0)',
      topic_id: topicId,
      video_count: 0,
      video_ratio: videoRatio,
      skipped_classification: true,
      http_status: 200
    }
  }];
}

return [{
  json: {
    success: true,
    production_register: productionRegister,
    topic_id: topicId,
    video_ratio: videoRatio,
    scene_count: sceneCount,
    video_count: videoCount,
    skipped_classification: false,
    started_at: new Date().toISOString(),
    http_status: 200
  }
}];

// Fetch all scenes for the topic from Supabase REST.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;
const topicId = data.topic_id;
const videoCount = data.video_count;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const scenesUrl = `${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&order=scene_number.asc&select=id,scene_number,narration_text,image_prompt,audio_duration_ms,chapter`;

let scenes = [];
try {
  const res = await fetch(scenesUrl, { method: 'GET', headers: sbHeaders });
  if (!res.ok) {
    const errText = await res.text();
    throw new Error(`HTTP ${res.status}: ${errText.slice(0, 300)}`);
  }
  scenes = await res.json();
} catch (e) {
  return [{
    json: {
      success: false,
      error: `Failed to fetch scenes: ${e.message}`,
      topic_id: topicId
    }
  }];
}

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{
    json: {
      success: false,
      error: 'No scenes found for topic — cannot classify',
      topic_id: topicId
    }
  }];
}

// Group chapters for distribution cap later
const chapterMap = {};
for (const s of scenes) {
  const ch = String(s.chapter || 'Unassigned').trim();
  if (!chapterMap[ch]) chapterMap[ch] = [];
  chapterMap[ch].push(s.scene_number);
}

return [{
  json: {
    topic_id: topicId,
    production_register: data.production_register || null,
    video_count: videoCount,
    video_ratio: data.video_ratio,
    scene_count: scenes.length,
    scenes,
    chapter_map: chapterMap,
    chapter_count: Object.keys(chapterMap).length,
    started_at: data.started_at
  }
}];

// Send scenes to Claude Opus 4.6 in batches of 30 for classification.
// Each scene classified as: motion_required / motion_beneficial / static_optimal.
// Inline exponential backoff (2s/4s/8s). Max 3 retries per batch.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;
if (data.success === false) return $input.item;

const scenes = data.scenes || [];
const videoCount = data.video_count;
const totalScenes = scenes.length;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const BATCH_SIZE = 30;
const allClassifications = [];

// Split into batches
const batches = [];
for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
  batches.push(scenes.slice(i, i + BATCH_SIZE));
}

for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
  const batch = batches[batchIdx];

  // Proportionally distribute video slots per batch
  const batchVideoSlots = Math.round(videoCount * (batch.length / totalScenes));

  const scenesBlock = batch.map(s => {
    const dur = s.audio_duration_ms ? `${(s.audio_duration_ms / 1000).toFixed(1)}s` : 'unknown';
    return `Scene ${s.scene_number} [${dur}] (Ch: ${s.chapter || 'N/A'}):\n  Narration: ${(s.narration_text || '').slice(0, 200)}\n  Image Prompt: ${(s.image_prompt || '').slice(0, 150)}`;
  }).join('\n\n');

  const systemPrompt = `You are a cinematic scene analyst for a documentary video production pipeline. You classify scenes by their motion requirements to determine which should receive AI-generated video (I2V) treatment versus remaining as Ken Burns still images.

Classification guide:
- motion_required: Scenes depicting physical action, movement, transformation, or sequences where stillness would feel unnatural (e.g., walking, driving, water flowing, crowds moving, machinery operating)
- motion_beneficial: Scenes that would noticeably benefit from subtle motion but work acceptably as stills (e.g., emotional close-ups, weather/atmosphere, slow reveals)
- static_optimal: Scenes where a still image with Ken Burns pan/zoom is ideal (e.g., data charts, landscapes, portraits, text overlays, abstract concepts, historical photos)

Be strict with motion_required — reserve it for scenes where stillness is genuinely jarring.`;

  const userPrompt = `Classify these ${batch.length} scenes. I need exactly ${batchVideoSlots} scenes selected for video treatment from this batch.

${scenesBlock}

Return ONLY valid JSON (no markdown fences):
{
  "classifications": [
    {
      "scene_number": <int>,
      "classification": "<motion_required|motion_beneficial|static_optimal>",
      "reasoning": "<1 sentence why>",
      "motion_intensity": <float 0.0-1.0>
    }
  ]
}`;

  let parsed = null;
  let lastError = null;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 4096,
          system: systemPrompt,
          messages: [{ role: 'user', content: userPrompt }]
        })
      });

      if (res.ok) {
        const body = await res.json();
        const text = body.content?.[0]?.text || '';
        const clean = text.replace(/```json|```/g, '').trim();

        try {
          parsed = JSON.parse(clean);
        } catch {
          const m = clean.match(/\{[\s\S]*\}/);
          if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
        }

        if (parsed && Array.isArray(parsed.classifications)) break;
        lastError = 'JSON parse failed';
        parsed = null;
      } else {
        const errBody = await res.text();
        lastError = `HTTP ${res.status}: ${errBody.slice(0, 200)}`;
        if (res.status === 429) await sleep(30000);
        if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
      }
    } catch (e) {
      lastError = e.message;
    }

    if (attempt < 3) {
      const delay = [2000, 4000, 8000][attempt - 1];
      await sleep(delay);
    }
  }

  if (parsed && Array.isArray(parsed.classifications)) {
    // Map by scene_number for quick lookup
    for (const c of parsed.classifications) {
      const valid = ['motion_required', 'motion_beneficial', 'static_optimal'].includes(c.classification);
      allClassifications.push({
        scene_number: c.scene_number,
        classification: valid ? c.classification : 'static_optimal',
        reasoning: String(c.reasoning || '').slice(0, 500),
        motion_intensity: Math.max(0, Math.min(1, parseFloat(c.motion_intensity) || 0))
      });
    }
  } else {
    // Fallback: mark entire batch as static_optimal
    for (const s of batch) {
      allClassifications.push({
        scene_number: s.scene_number,
        classification: 'static_optimal',
        reasoning: `Classification fallback (batch ${batchIdx + 1} failed: ${lastError || 'unknown'})`,
        motion_intensity: 0
      });
    }
  }

  // Inter-batch delay to avoid rate limiting
  if (batchIdx + 1 < batches.length) {
    await sleep(1500);
  }
}

return [{
  json: {
        production_register: data.production_register || null,
topic_id: data.topic_id,
    video_count: videoCount,
    video_ratio: data.video_ratio,
    scene_count: totalScenes,
    chapter_map: data.chapter_map,
    chapter_count: data.chapter_count,
    all_classifications: allClassifications,
    batches_processed: batches.length,
    started_at: data.started_at
  }
}];

// Collect all classifications. Sort by priority (motion_required first, then
// motion_beneficial). Select top N scenes (N = video_count). Distribute across
// chapters (cap at 40% of video_count per chapter to prevent clustering).

const data = $input.first().json;
if (data.success === false) return $input.item;

const classifications = data.all_classifications || [];
const videoCount = data.video_count;
const chapterMap = data.chapter_map || {};
const chapterCount = data.chapter_count || 1;

// Priority ordering:
// 1. motion_required — sorted by motion_intensity desc
// 2. motion_beneficial — sorted by motion_intensity desc
// 3. static_optimal — never selected unless we must fill quota
const priorityOrder = { 'motion_required': 0, 'motion_beneficial': 1, 'static_optimal': 2 };

const sorted = [...classifications].sort((a, b) => {
  const pA = priorityOrder[a.classification] ?? 2;
  const pB = priorityOrder[b.classification] ?? 2;
  if (pA !== pB) return pA - pB;
  return (b.motion_intensity || 0) - (a.motion_intensity || 0);
});

// Build reverse map: scene_number -> chapter name
const sceneToChapter = {};
for (const [chName, sceneNums] of Object.entries(chapterMap)) {
  for (const sn of sceneNums) {
    sceneToChapter[sn] = chName;
  }
}

// Per-chapter cap: max 40% of total video_count per chapter
const maxPerChapter = Math.max(1, Math.ceil(videoCount * 0.4));
const chapterCounts = {};
for (const ch of Object.keys(chapterMap)) {
  chapterCounts[ch] = 0;
}

const selected = [];
const remaining = [];

for (const item of sorted) {
  if (selected.length >= videoCount) {
    remaining.push(item);
    continue;
  }

  const ch = sceneToChapter[item.scene_number] || 'Unassigned';
  const currentCount = chapterCounts[ch] || 0;

  if (currentCount >= maxPerChapter) {
    // Cap exceeded for this chapter — defer to remaining
    remaining.push(item);
    continue;
  }

  selected.push(item);
  chapterCounts[ch] = currentCount + 1;
}

// If we still need more (cap deferred some), fill from remaining
if (selected.length < videoCount && remaining.length > 0) {
  const need = videoCount - selected.length;
  const overflow = remaining
    .filter(r => !selected.some(s => s.scene_number === r.scene_number))
    .slice(0, need);
  selected.push(...overflow);
}

const selectedSceneNumbers = new Set(selected.map(s => s.scene_number));

// Build classification map for all scenes
const classificationMap = {};
for (const c of classifications) {
  classificationMap[c.scene_number] = {
    classification: c.classification,
    reasoning: c.reasoning,
    motion_intensity: c.motion_intensity,
    has_video: selectedSceneNumbers.has(c.scene_number)
  };
}

return [{
  json: {
        production_register: data.production_register || null,
topic_id: data.topic_id,
    video_count: videoCount,
    actual_selected: selected.length,
    video_ratio: data.video_ratio,
    scene_count: data.scene_count,
    selected_scene_numbers: [...selectedSceneNumbers].sort((a, b) => a - b),
    classification_map: classificationMap,
    chapter_distribution: chapterCounts,
    started_at: data.started_at
  }
}];

// For each selected video scene, call Claude to determine optimal 10-second
// window placement within the scene's duration. Batch all selected scenes
// in one call to minimize API cost.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;
if (data.success === false) return $input.item;

const selectedNumbers = data.selected_scene_numbers || [];
const classMap = data.classification_map || {};

if (selectedNumbers.length === 0) {
  return [{
    json: {
      ...data,
      placement_results: {},
      placement_cost_usd: 0
    }
  }];
}

const anthropicKey = $env.ANTHROPIC_API_KEY;
const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Fetch full scene data for selected scenes to get narration + duration
const idFilter = selectedNumbers.map(n => `scene_number.eq.${n}`).join(',');
const scenesUrl = `${supabaseUrl}/rest/v1/scenes?topic_id=eq.${data.topic_id}&or=(${idFilter})&select=scene_number,narration_text,audio_duration_ms,image_prompt&order=scene_number.asc`;

let selectedScenes = [];
try {
  const res = await fetch(scenesUrl, { method: 'GET', headers: sbHeaders });
  if (res.ok) selectedScenes = await res.json();
} catch (_) { /* fallback below */ }

// Build prompt for placement
const scenesBlock = selectedScenes.map(s => {
  const durMs = s.audio_duration_ms || 10000;
  const durSec = (durMs / 1000).toFixed(1);
  return `Scene ${s.scene_number} [${durSec}s total]:\n  Narration: ${(s.narration_text || '').slice(0, 150)}\n  Visual: ${(s.image_prompt || '').slice(0, 100)}`;
}).join('\n\n');

const placementPrompt = `For each documentary scene below, determine the optimal 10-second window for AI video generation within its total duration.

Rules:
- The video clip is exactly 10 seconds (10000ms)
- It must fit within the scene's total duration (start_ms + 10000 <= total_duration_ms)
- Place the video at the most visually dynamic moment in the narration
- If scene is shorter than 12 seconds, start at 0ms
- Prefer placing video at emotional peaks, action moments, or reveal points

Scenes:
${scenesBlock}

Return ONLY valid JSON (no markdown fences):
{
  "placements": [
    {
      "scene_number": <int>,
      "start_ms": <int>,
      "end_ms": <int>,
      "placement_reason": "<1 sentence>"
    }
  ]
}`;

let placements = null;
let placementCost = 0;

for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-opus-4-6',
        max_tokens: 2048,
        messages: [{ role: 'user', content: placementPrompt }]
      })
    });

    if (res.ok) {
      const body = await res.json();
      const text = body.content?.[0]?.text || '';
      const clean = text.replace(/```json|```/g, '').trim();
      try {
        placements = JSON.parse(clean);
      } catch {
        const m = clean.match(/\{[\s\S]*\}/);
        if (m) { try { placements = JSON.parse(m[0]); } catch {} }
      }
      if (placements && Array.isArray(placements.placements)) {
        placementCost = 0.03;
        break;
      }
      placements = null;
    } else if (res.status === 429) {
      await sleep(30000);
    }
  } catch (_) { }

  if (attempt < 3) await sleep(Math.min(2000 * Math.pow(2, attempt - 1), 8000));
}

// Build placement map
const placementMap = {};
if (placements && Array.isArray(placements.placements)) {
  for (const p of placements.placements) {
    const sceneData = selectedScenes.find(s => s.scene_number === p.scene_number);
    const totalMs = sceneData?.audio_duration_ms || 30000;
    let startMs = Math.max(0, parseInt(p.start_ms) || 0);
    let endMs = startMs + 10000;

    // Clamp to scene duration
    if (endMs > totalMs) {
      startMs = Math.max(0, totalMs - 10000);
      endMs = startMs + 10000;
    }

    placementMap[p.scene_number] = {
      start_ms: startMs,
      end_ms: endMs,
      placement_reason: String(p.placement_reason || '').slice(0, 300)
    };
  }
}

// Fill defaults for any missing placements
for (const sn of selectedNumbers) {
  if (!placementMap[sn]) {
    placementMap[sn] = {
      start_ms: 0,
      end_ms: 10000,
      placement_reason: 'Default placement (beginning of scene)'
    };
  }
}

return [{
  json: {
    ...data,
    placement_map: placementMap,
    placement_cost_usd: placementCost
  }
}];

// Batch PATCH all scenes with classification results.
// For video scenes: has_video=true, video_placement_start_ms, video_placement_end_ms,
//   scene_classification, classification_reasoning
// For non-video scenes: has_video=false, scene_classification, classification_reasoning
// Also INSERT scene_classifications JSONB into cost_calculator_snapshots.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;
if (data.success === false) return $input.item;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const classMap = data.classification_map || {};
const placementMap = data.placement_map || {};
const selectedSet = new Set(data.selected_scene_numbers || []);
const productionRegister = data.production_register || null;

let patchErrors = [];
let patchCount = 0;

// Batch patch by scene_number. Supabase REST does not support bulk PATCH with
// different bodies per row, so we loop. For efficiency, batch non-video scenes
// in a single PATCH (they share the same has_video=false fields minus reasoning).

// Video scenes — individual patches (each has unique placement data)
for (const sn of data.selected_scene_numbers || []) {
  const cls = classMap[sn] || {};
  const placement = placementMap[sn] || { start_ms: 0, end_ms: 10000 };

  const body = {
    has_video: true,
    video_placement_start_ms: placement.start_ms,
    video_placement_end_ms: placement.end_ms,
    scene_classification: cls.classification || 'motion_beneficial',
    classification_reasoning: `${cls.reasoning || ''} | Placement: ${placement.placement_reason || ''}`.slice(0, 1000)
  };
  body.production_register = productionRegister;

  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&scene_number=eq.${sn}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(body)
    });
    if (!res.ok) {
      patchErrors.push(`Scene ${sn}: HTTP ${res.status}`);
    } else {
      patchCount++;
    }
  } catch (e) {
    patchErrors.push(`Scene ${sn}: ${e.message}`);
  }
}

// Non-video scenes — batch by classification type for fewer PATCHes
const byClassification = {};
for (const [snStr, cls] of Object.entries(classMap)) {
  const sn = parseInt(snStr, 10);
  if (selectedSet.has(sn)) continue; // already patched above
  const key = cls.classification || 'static_optimal';
  if (!byClassification[key]) byClassification[key] = [];
  byClassification[key].push(sn);
}

for (const [classification, sceneNumbers] of Object.entries(byClassification)) {
  // Supabase supports filter-based PATCH on multiple rows
  // We can batch all scenes of same classification type
  const filter = sceneNumbers.map(n => `scene_number.eq.${n}`).join(',');
  const body = {
    has_video: false,
    scene_classification: classification,
    classification_reasoning: 'Not selected for video treatment'
  };
  body.production_register = productionRegister;

  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&or=(${filter})`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(body)
    });
    if (!res.ok) {
      patchErrors.push(`Batch ${classification}: HTTP ${res.status}`);
    } else {
      patchCount += sceneNumbers.length;
    }
  } catch (e) {
    patchErrors.push(`Batch ${classification}: ${e.message}`);
  }
}

// Insert classification snapshot into cost_calculator_snapshots
try {
  const snapshot = {
    topic_id: topicId,
    video_count: data.actual_selected || data.video_count,
    video_ratio: data.video_ratio,
    selected_scene_numbers: data.selected_scene_numbers,
    chapter_distribution: data.chapter_distribution,
    classification_summary: {
      motion_required: Object.values(classMap).filter(c => c.classification === 'motion_required').length,
      motion_beneficial: Object.values(classMap).filter(c => c.classification === 'motion_beneficial').length,
      static_optimal: Object.values(classMap).filter(c => c.classification === 'static_optimal').length
    },
    classified_at: new Date().toISOString()
  };

  // Upsert: check if row exists for this topic_id
  const existingRes = await fetch(`${supabaseUrl}/rest/v1/cost_calculator_snapshots?topic_id=eq.${topicId}&select=id&limit=1`, {
    method: 'GET',
    headers: sbHeaders
  });
  const existing = existingRes.ok ? await existingRes.json() : [];

  if (Array.isArray(existing) && existing.length > 0) {
    await fetch(`${supabaseUrl}/rest/v1/cost_calculator_snapshots?topic_id=eq.${topicId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ scene_classifications: snapshot })
    });
  } else {
    await fetch(`${supabaseUrl}/rest/v1/cost_calculator_snapshots`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        topic_id: topicId,
        scene_classifications: snapshot
      })
    });
  }
} catch (_) { /* snapshot logging best-effort */ }

return [{
  json: {
