// PATCH topics SET pipeline_stage='tts' to resume the pipeline, then POST /webhook/production/trigger to start TTS.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
let pipelineError = null;
let productionError = null;

try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      pipeline_stage: 'tts',
      last_status_change: new Date().toISOString()
    })
  });
  if (!res.ok) {
    const errText = await res.text();
    pipelineError = `PATCH pipeline_stage failed: HTTP ${res.status}: ${errText.slice(0, 200)}`;
  }
} catch (e) {
  pipelineError = `PATCH pipeline_stage exception: ${e.message}`;
}

// Kick off production (TTS/images) now that scenes are classified
if (!pipelineError) {
  try {
    const webhookBase = $env.N8N_WEBHOOK_BASE;
    const token = $env.DASHBOARD_API_TOKEN;
    const prodRes = await fetch(`${webhookBase}/production/trigger`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ topic_id: topicId })
    });
    if (!prodRes.ok) {
      const errText = await prodRes.text();
      productionError = `POST /production/trigger failed: HTTP ${prodRes.status}: ${errText.slice(0, 200)}`;
    }
  } catch (e) {
    productionError = `POST /production/trigger exception: ${e.message}`;
  }
}

return [{
  json: {
    ...data,
    pipeline_stage_updated: !pipelineError,
    pipeline_error: pipelineError,
    production_triggered: !productionError,
    production_error: productionError
  }
}];

// INSERT into production_logs: stage='scene_classify', action='completed',
// details with video_count, cost_usd.
// Global fetch + $env per MEMORY.md.

const data = $input.first().json;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const durationMs = data.started_at ? Date.now() - new Date(data.started_at).getTime() : 0;

// Estimate classification API cost:
// - Classification batches: ~$0.02 per batch of 30 scenes (Opus 4.6)
// - Placement call: data.placement_cost_usd
const batchCount = Math.ceil((data.scene_count || 0) / 30);
const classifyCost = batchCount * 0.02;
const totalCost = classifyCost + (data.placement_cost_usd || 0);

try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      topic_id: topicId,
      stage: 'scene_classify',
      scene_number: null,
      action: 'completed',
      status: (data.patch_errors && data.patch_errors.length > 0) ? 'partial' : 'success',
      duration_ms: durationMs,
      cost_usd: Math.round(totalCost * 1000) / 1000,
      retry_count: 0
    })
  });
} catch (_) { /* logging best-effort */ }

return [{
  json: {
    success: true,
    topic_id: topicId,
    video_count: data.video_count,
    actual_selected: data.actual_selected,
    video_ratio: data.video_ratio,
    scene_count: data.scene_count,
    scenes_patched: data.scenes_patched,
    selected_scene_numbers: data.selected_scene_numbers,
    chapter_distribution: data.chapter_distribution,
    pipeline_stage_updated: data.pipeline_stage_updated,
    duration_ms: durationMs,
    estimated_cost_usd: Math.round(totalCost * 1000) / 1000,
    patch_errors: data.patch_errors || [],
    completed_at: new Date().toISOString()
  }
}];
